Bash(node -e "
const data = JSON.parse\(require\('fs'\).readFileSync\('cache.json'\)\);
const spots = data.spots.filter\(s => s.source === 'places'\);

// Check names for obvious non-gozleme indicators
const suspicious = spots.filter\(s => {
  const n = s.name.toLowerCase\(\);
  const hasGozleme = n.includes\('gozleme'\) || n.includes\('gözleme'\);
  return !hasGozleme;
}\);

const withGozleme = spots.length - suspicious.length;
console.log\('Places spots total:', spots.length\);
console.log\('Has gozleme in name:', withGozleme\);
console.log\('No gozleme in name:', suspicious.length, '\(' + Math.round\(suspicious.length/spots.length*100\) + '%\)'\);

// Show a broader sample of suspicious ones
console.log\('\\nSample of spots WITHOUT gozleme in the name:'\);
suspicious.slice\(0, 60\).forEach\(\(s,i\) => console.log\(i+1+'.', s.name\)\);
")

